      CREATE OR REPLACE FUNCTION notify_hl7_patient_visit_created()
RETURNS TRIGGER AS $function$
      BEGIN
      INSERT INTO ${hl7.integrationSchema}.hl7_event (
        id,
        event_type,
        object_key,
        event_datetime
      )
      VALUES (
               gen_random_uuid()::varchar,
               '${hl7.events.patientVisitCreated}',
               NEW.id::varchar,
               NOW()
             );

      RETURN NEW;
      END;
      $function$ LANGUAGE plpgsql;


DROP TRIGGER IF EXISTS trg_hl7_patient_visit_created ON patient_encounters;

CREATE TRIGGER trg_hl7_patient_visit_created
  AFTER INSERT ON patient_encounters
  FOR EACH ROW
  EXECUTE FUNCTION notify_hl7_patient_visit_created();
